class Solution {
public:
    long long countGoodIntegers(int n, int k) {
        long long count = 0;
        for (long long i = 1; i <= 9; ++i) {
            for (int j = 0; j < n - 1; ++j) {
                for (long long l = 0; l <= 9; ++l) {
                    string s = to_string(i) + string(n - 1, '0') + to_string(l);
                    if (isKPalindrome(s, k)) {
                        count++;
                    }
                }
            }
        }
        return count;
    }
    bool isKPalindrome(string s, int k) {
        int left = 0;
        int right = s.size() - 1;
        while (left < right) {
            if (s[left] != s[right]) {
                return false;
            }
            left++;
            right--;
        }
        return (s % k == 0);
    }
};
